CREATE TABLE IF NOT EXISTS cvs (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,template_slug VARCHAR(40) NOT NULL DEFAULT 'classic',data_json JSON NOT NULL,updated_at TIMESTAMP NULL DEFAULT NULL,FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS export_tokens (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,token VARCHAR(64) NOT NULL UNIQUE,expires_at DATETIME NOT NULL,used_at DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS analytics_events (id BIGINT AUTO_INCREMENT PRIMARY KEY,event_type ENUM('visit','signup','export','ad_page_view') NOT NULL DEFAULT 'visit',route VARCHAR(255) NULL,user_id INT NULL,session_id VARCHAR(128) NULL,user_agent VARCHAR(255) NULL,ip VARCHAR(64) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(event_type),INDEX(created_at),INDEX(user_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS ad_slots (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,placement ENUM('interstitial','sidebar','banner','dashboard') NOT NULL DEFAULT 'interstitial',ad_code MEDIUMTEXT NOT NULL,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
